# Disallow all Jinja statements/controls and filters to prevent SSTI.
_ALLOWED_VAR_EXPR = re.compile(
    r"""
    \A
    \s*\{\{\s*user(?:\.[A-Za-z_][A-Za-z0-9_]*)*\s*\}\}\s*
    \Z
    """,
    re.VERBOSE,
)


def _escape_html(value: Any) -> str:
    """Minimal HTML escaping using built-in functionality only."""
    s = "" if value is None else str(value)
    return (
        s.replace("&", "&amp;")
        .replace("<", "&lt;")
        .replace(">", "&gt;")
        .replace('"', "&quot;")
        .replace("'", "&#x27;")
    )


def _safe_user_info(user_info: Dict[str, Any]) -> Dict[str, Any]:
    """
    Recursively HTML-escape user-provided values so they render safely even if autoescape
    isn't enabled for render_template_string.
    """
    def sanitize(v: Any) -> Any:
        if isinstance(v, dict):
            return {str(k): sanitize(val) for k, val in v.items()}
        if isinstance(v, (list, tuple)):
            return [sanitize(x) for x in v]
        return _escape_html(v)

    return sanitize(user_info)


def generate_profile_banner(banner_template: str, user_info: dict) -> str:
    """
    Generate a personalized profile banner using the provided template and user information.

    Security: Prevent SSTI by only allowing very limited interpolation expressions and
    rejecting any template containing Jinja statements/controls/filters.
