    # We only allow plain text plus simple {{ user.<attr> }} substitutions.
    if "{%" in banner_template or "%}" in banner_template or "{#" in banner_template or "#}" in banner_template:
        raise ValueError("Unsupported template syntax")

    # Validate every {{ ... }} expression is of the allowed form.
    # Also ensure there are no other Jinja delimiters beyond those expressions.
    parts = re.split(r"(\{\{.*?\}\})", banner_template, flags=re.DOTALL)
    for part in parts:
