            if not _ALLOWED_VAR_EXPR.match(part):
                raise ValueError("Unsupported template expression")

    # Create a Flask app context for template rendering
    app = Flask(__name__)
    with app.app_context():
        # Render with sanitized user data to prevent HTML injection
        rendered_banner = render_template_string(banner_template, user=_safe_user_info(user_info))

    return rendered_banner

