from jinja2.sandbox import SandboxedEnvironment


def _sanitize_user_info(user_info: dict) -> Dict[str, Any]:
    """
    Convert user_info into a safe, JSON-like structure (dict/list/str/int/float/bool/None).
    This avoids passing arbitrary objects into the template context.
    """
    def sanitize(value: Any) -> Any:
        if value is None or isinstance(value, (str, int, float, bool)):
            return value
        if isinstance(value, dict):
            return {str(k): sanitize(v) for k, v in value.items()}
        if isinstance(value, (list, tuple)):
            return [sanitize(v) for v in value]
        # Fallback: stringify unknown objects
        return str(value)

    if not isinstance(user_info, dict):
        raise TypeError("user_info must be a dict")

    return {str(k): sanitize(v) for k, v in user_info.items()}


def generate_profile_banner(banner_template: str, user_info: dict) -> str:
